// src/context/PlayerIdentityContext.js
import React, {
  createContext,
  useContext,
  useState,
  useEffect,
  useCallback,
} from 'react';
import { fetchPlayerByToken } from '../lib/db';
import { getStoredToken, storeToken, clearToken } from '../lib/session';

const PlayerIdentityContext = createContext();

export function PlayerIdentityProvider({ leagueId, initialPlayer, children }) {
  // initialPlayer: passed directly from App after launch — skips the picker entirely
  const [currentPlayer, setCurrentPlayer] = useState(initialPlayer || null);
  const [loading, setLoading] = useState(!initialPlayer && !!leagueId);

  // If no initialPlayer, check localStorage for a stored token
  useEffect(() => {
    if (initialPlayer || !leagueId) {
      setLoading(false);
      return;
    }

    const stored = getStoredToken(leagueId);
    if (!stored) {
      setLoading(false);
      return;
    }

    fetchPlayerByToken(stored)
      .then((player) => {
        if (player && player.leagueId === leagueId) {
          setCurrentPlayer(player);
        } else {
          clearToken(leagueId);
        }
      })
      .catch(() => clearToken(leagueId))
      .finally(() => setLoading(false));
  }, [leagueId, initialPlayer]);

  const loginWithToken = useCallback(
    async (token) => {
      // In-memory mode: leagueId is null, so just accept any token input
      // that matches a participant's sessionToken (handled by fetchPlayerByToken)
      const player = leagueId ? await fetchPlayerByToken(token.trim()) : null;

      if (leagueId && (!player || player.leagueId !== leagueId)) {
        throw new Error('Code not found. Check the code and try again.');
      }

      if (player) {
        storeToken(leagueId, token.trim());
        setCurrentPlayer(player);
        return player;
      }

      throw new Error('Code not found. Check the code and try again.');
    },
    [leagueId],
  );

  const logout = useCallback(() => {
    if (leagueId) clearToken(leagueId);
    setCurrentPlayer(null);
  }, [leagueId]);

  const isAdmin = currentPlayer?.role === 'admin';

  return (
    <PlayerIdentityContext.Provider
      value={{ currentPlayer, loading, loginWithToken, logout, isAdmin }}
    >
      {children}
    </PlayerIdentityContext.Provider>
  );
}

export function usePlayerIdentity() {
  return useContext(PlayerIdentityContext);
}
